const adminOverviewCounts = `-- name: AdminOverviewCounts :one

SELECT
  (SELECT COUNT(*)::bigint FROM merchants) AS merchant_count,
  (SELECT COUNT(*)::bigint FROM users u
     WHERE EXISTS (
       SELECT 1 FROM orders o WHERE o.buyer_user_id = u.id
     ) OR EXISTS (
       SELECT 1 FROM auth_sessions s WHERE s.user_id = u.id AND s.surface = 'BUYER'
     )) AS buyer_count,
  (SELECT COUNT(*)::bigint FROM orders) AS order_count,
  (SELECT COUNT(*)::bigint FROM payment_intents) AS payment_count,
  (SELECT COUNT(*)::bigint FROM withdrawals WHERE status IN (
    'REQUESTED', 'UNDER_REVIEW', 'HELD', 'APPROVED', 'PROCESSING', 'UNKNOWN_OUTCOME'
  )) AS pending_withdrawal_count,
  (SELECT COUNT(*)::bigint FROM kyc_cases WHERE status IN (
    'SUBMITTED', 'IN_REVIEW', 'VENDOR_CHECK', 'NEEDS_CLARIFICATION'
  )) AS open_kyc_count,
  (SELECT COALESCE(SUM(amount_idr), 0)::bigint FROM payment_intents WHERE status = 'PAID') AS gross_volume_paid_idr,
  (SELECT COALESCE(SUM(fee_idr), 0)::bigint FROM orders WHERE payment_status = 'PAID') AS platform_fee_paid_idr,
  (SELECT COUNT(*)::bigint FROM payment_intents WHERE status = 'PAID') AS paid_payment_count,
  (SELECT COUNT(*)::bigint FROM payment_intents WHERE status IN (
    'PAID', 'FAILED', 'EXPIRED', 'CANCELLED'
  )) AS terminal_payment_count
`

type AdminOverviewCountsRow struct {
	MerchantCount          int64 `json:"merchant_count"`
	BuyerCount             int64 `json:"buyer_count"`
	OrderCount             int64 `json:"order_count"`
	PaymentCount           int64 `json:"payment_count"`
	PendingWithdrawalCount int64 `json:"pending_withdrawal_count"`
	OpenKycCount           int64 `json:"open_kyc_count"`
	GrossVolumePaidIdr     int64 `json:"gross_volume_paid_idr"`
	PlatformFeePaidIdr     int64 `json:"platform_fee_paid_idr"`
	PaidPaymentCount       int64 `json:"paid_payment_count"`
	TerminalPaymentCount   int64 `json:"terminal_payment_count"`
}

// BE-500 admin read models (permissioned projections; never secrets/raw payloads).
func (q *Queries) AdminOverviewCounts(ctx context.Context) (AdminOverviewCountsRow, error) {
	row := q.db.QueryRow(ctx, adminOverviewCounts)
	var i AdminOverviewCountsRow
	err := row.Scan(
		&i.MerchantCount,
		&i.BuyerCount,
		&i.OrderCount,
		&i.PaymentCount,
		&i.PendingWithdrawalCount,
		&i.OpenKycCount,
		&i.GrossVolumePaidIdr,
		&i.PlatformFeePaidIdr,
		&i.PaidPaymentCount,
		&i.TerminalPaymentCount,
	)
	return i, err
}

const adminPlatformVolumeHours = `-- name: AdminPlatformVolumeHours :many
SELECT COALESCE(SUM(pi.amount_idr), 0)::bigint AS volume_idr
FROM generate_series(
  date_trunc('hour', now() AT TIME ZONE 'UTC') - interval '23 hours',
  date_trunc('hour', now() AT TIME ZONE 'UTC'),
  interval '1 hour'
) AS hour_bucket
LEFT JOIN payment_intents pi
  ON pi.status = 'PAID'
 AND date_trunc('hour', COALESCE(pi.updated_at, pi.created_at) AT TIME ZONE 'UTC') = hour_bucket
GROUP BY hour_bucket
ORDER BY hour_bucket ASC
`

func (q *Queries) AdminPlatformVolumeHours(ctx context.Context) ([]int64, error) {
	rows, err := q.db.Query(ctx, adminPlatformVolumeHours)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []int64{}
	for rows.Next() {
		var volume_idr int64
		if err := rows.Scan(&volume_idr); err != nil {
			return nil, err
		}
		items = append(items, volume_idr)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}
